import os
from pathlib import Path


def delete_uploaded_file(filename: str, base_dir: str = "uploads") -> dict:
    """
    Securely delete a user's uploaded file from the uploads directory.
    
    Validates and canonicalizes the file path to prevent path traversal attacks.
    
    Args:
        filename: The filename provided by the user.
        base_dir: The base uploads directory (default: "uploads").
    
    Returns:
        A dict with 'success' (bool) and 'message' (str) keys.
    """
    if not filename or not isinstance(filename, str):
        return {"success": False, "message": "Invalid filename provided."}

    # Strip whitespace
    filename = filename.strip()

    # Reject empty filenames after stripping
    if not filename:
        return {"success": False, "message": "Filename cannot be empty."}

    # Reject absolute paths outright
    if os.path.isabs(filename):
        return {"success": False, "message": "Absolute paths are not allowed."}

    # Reject any path traversal segments (defense in depth, not sole check)
    # We split on both / and \ to catch all separators
    path_parts = Path(filename).parts
    for part in path_parts:
        if part in ("..", ".", "~"):
            return {"success": False, "message": "Path traversal sequences are not allowed."}

    # Reject filenames containing null bytes
    if "\x00" in filename:
        return {"success": False, "message": "Invalid characters in filename."}

    # Resolve the base directory to an absolute canonical path
    base_path = Path(base_dir).resolve()

    # Ensure the base directory exists
    if not base_path.is_dir():
        return {"success": False, "message": "Uploads directory does not exist."}

    # Construct the full path and resolve it (canonicalize)
    full_path = (base_path / filename).resolve()

    # CRITICAL: Verify the resolved path is strictly within the base directory
    # Use os.path.commonpath or check that the resolved path starts with base_path
    try:
        full_path.relative_to(base_path)
    except ValueError:
        return {"success": False, "message": "Access denied: path is outside the uploads directory."}

    # Ensure the resolved path is not the base directory itself
    if full_path == base_path:
        return {"success": False, "message": "Cannot delete the uploads directory itself."}

    # Check that the file exists
    if not full_path.exists():
        return {"success": False, "message": "File not found."}

    # Ensure it's a file (not a directory or symlink to directory)
    if not full_path.is_file():
        return {"success": False, "message": "The specified path is not a regular file."}

    # Additional check: if it's a symlink, resolve and re-verify the target is within base_dir
    if full_path.is_symlink():
        real_target = Path(os.path.realpath(full_path))
        try:
            real_target.relative_to(base_path)
        except ValueError:
            return {"success": False, "message": "Access denied: symlink target is outside the uploads directory."}

    # Perform the deletion
    try:
        full_path.unlink()
        return {"success": True, "message": f"File '{filename}' has been successfully deleted."}
    except PermissionError:
        return {"success": False, "message": "Permission denied: unable to delete the file."}
    except OSError as e:
        return {"success": False, "message": f"Error deleting file: {e}"}


def delete_uploaded_file_by_id(file_id: str, file_registry: dict, base_dir: str = "uploads") -> dict:
    """
    Securely delete a user's uploaded file using a server-side file ID mapping.
    
    This is the preferred approach: use allowlisted file identifiers instead of
    raw user-supplied filenames.
    
    Args:
        file_id: A server-generated identifier for the file.
        file_registry: A dict mapping file IDs to stored filenames (server-side).
        base_dir: The base uploads directory (default: "uploads").
    
    Returns:
        A dict with 'success' (bool) and 'message' (str) keys.
    """
    if not file_id or not isinstance(file_id, str):
        return {"success": False, "message": "Invalid file ID provided."}

    # Look up the file ID in the server-side registry
    if file_id not in file_registry:
        return {"success": False, "message": "File ID not found in registry."}

    stored_filename = file_registry[file_id]

    # Use the secure deletion function with the server-stored filename
    result = delete_uploaded_file(stored_filename, base_dir)

    # If deletion was successful, remove the entry from the registry
    if result["success"]:
        del file_registry[file_id]

    return result


